import React from "react";
import "./Welcome.css";
import avatar from "../assets/robot-avatar.png";

export default function Welcome() {
  return (
    <div className="hero">
      <div className="hero-content">
        <img src={avatar} alt="MindCare AI" className="hero-avatar" />

        <h1>Hi, I’m MindCare</h1>
        <p>
          A calm, supportive AI therapist.<br />
          You can talk to me about anything.
        </p>

        <button className="start-btn">Start Conversation</button>

        <div className="auth-links">
          <span>Login</span>
          <span>Sign Up</span>
        </div>
      </div>
    </div>
  );
}
